 using System.Text.Json;
 using System.Text.Json.Serialization;
 using System.Text.Json.Serialization.Metadata;

 // --- 1. Strongly-typed metadata retrieval ---
 JsonSerializerOptions options = MyContext.Default.Options;

 // GetTypeInfo<T>() returns JsonTypeInfo<T> directly — no cast needed
 JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
 Console.WriteLine($"Typed metadata  : {personInfo.Type.Name}");
 Console.WriteLine($"  Return type   : {personInfo.GetType().Name}");

 // --- 2. Probe without throwing ---
 // Person IS in the context → returns true
 if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? found))
     Console.WriteLine($"Probe Person    : found ({found!.Type.Name})");
 else
     Console.WriteLine("Probe Person    : not found");

 // Order is NOT in the context → returns false, no exception
 if (options.TryGetTypeInfo<Order>(out JsonTypeInfo<Order>? missing))
     Console.WriteLine($"Probe Order     : found ({missing!.Type.Name})");
 else
     Console.WriteLine("Probe Order     : not found (no exception thrown)");

 // Types
 record Person(string Name, int Age);
 record Order(int Id, decimal Total);

 // Source-gen context — only knows about Person
 [JsonSerializable(typeof(Person))]
 partial class MyContext : JsonSerializerContext;
